import React, { useState } from 'react';
import { sendEmailCode, sendPhoneCode, verifyCode } from '../api/api';
import LanguageSwitcher from './LanguageSwitcher';

function Verify({ user, onVerified, onBack }) {
  const [emailCode, setEmailCode] = useState('');
  const [phoneCode, setPhoneCode] = useState('');
  const [emailVerified, setEmailVerified] = useState(false);
  const [phoneVerified, setPhoneVerified] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');

  const handleSendEmailCode = async () => {
    setLoading(true);
    try {
      await sendEmailCode(user.email);
      setMessage('📧 Code envoyé à votre email');
    } catch (error) {
      setMessage('❌ Erreur lors de l\'envoi');
    } finally {
      setLoading(false);
    }
  };

  const handleSendPhoneCode = async () => {
    setLoading(true);
    try {
      await sendPhoneCode(user.phone);
      setMessage('📱 Code envoyé à votre téléphone');
    } catch (error) {
      setMessage('❌ Erreur lors de l\'envoi');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyEmail = async () => {
    if (emailCode.length !== 6) {
      setMessage('❌ Le code doit contenir 6 chiffres');
      return;
    }
    setLoading(true);
    try {
      const result = await verifyCode(user.email, emailCode, 'email');
      if (result.valid) {
        setEmailVerified(true);
        setMessage('✅ Email vérifié avec succès');
      } else {
        setMessage('❌ Code email invalide');
      }
    } catch (error) {
      setMessage('❌ Erreur de vérification');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyPhone = async () => {
    if (phoneCode.length !== 6) {
      setMessage('❌ Le code doit contenir 6 chiffres');
      return;
    }
    setLoading(true);
    try {
      const result = await verifyCode(user.phone, phoneCode, 'phone');
      if (result.valid) {
        setPhoneVerified(true);
        setMessage('✅ Téléphone vérifié avec succès');
      } else {
        setMessage('❌ Code téléphone invalide');
      }
    } catch (error) {
      setMessage('❌ Erreur de vérification');
    } finally {
      setLoading(false);
    }
  };

  const handleContinue = () => {
    if (emailVerified && phoneVerified) {
      onVerified();
    } else {
      setMessage('❌ Veuillez vérifier votre email et votre téléphone');
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <button style={styles.backBtn} onClick={onBack}>← Retour</button>
        <h1 style={styles.title}>🔐 Vérification</h1>
        <LanguageSwitcher />
        <p style={styles.subtitle}>Vérifiez votre identité pour activer votre compte</p>

        {/* Vérification Email */}
        <div style={styles.verifyBox}>
          <h3>📧 Vérification Email</h3>
          <p style={styles.info}>Email: <strong>{user.email}</strong></p>
          <button 
            onClick={handleSendEmailCode} 
            style={styles.sendBtn}
            disabled={loading || emailVerified}
          >
            {emailVerified ? '✅ Vérifié' : '📨 Envoyer le code'}
          </button>
          {!emailVerified && (
            <div style={styles.codeInput}>
              <input
                type="text"
                placeholder="Code 6 chiffres"
                maxLength="6"
                value={emailCode}
                onChange={(e) => setEmailCode(e.target.value.replace(/\D/g, ''))}
                style={styles.input}
              />
              <button 
                onClick={handleVerifyEmail} 
                style={styles.verifyBtn}
                disabled={loading}
              >
                🔑 Vérifier
              </button>
            </div>
          )}
        </div>

        {/* Vérification Téléphone */}
        <div style={styles.verifyBox}>
          <h3>📱 Vérification Téléphone</h3>
          <p style={styles.info}>Téléphone: <strong>{user.phone || 'Non renseigné'}</strong></p>
          <button 
            onClick={handleSendPhoneCode} 
            style={styles.sendBtn}
            disabled={loading || phoneVerified}
          >
            {phoneVerified ? '✅ Vérifié' : '📨 Envoyer le code'}
          </button>
          {!phoneVerified && (
            <div style={styles.codeInput}>
              <input
                type="text"
                placeholder="Code 6 chiffres"
                maxLength="6"
                value={phoneCode}
                onChange={(e) => setPhoneCode(e.target.value.replace(/\D/g, ''))}
                style={styles.input}
              />
              <button 
                onClick={handleVerifyPhone} 
                style={styles.verifyBtn}
                disabled={loading}
              >
                🔑 Vérifier
              </button>
            </div>
          )}
        </div>

        {message && <p style={styles.message}>{message}</p>}

        <button 
          onClick={handleContinue} 
          style={styles.continueBtn}
          disabled={!emailVerified || !phoneVerified}
        >
          {emailVerified && phoneVerified ? '🚀 Continuer' : '⏳ Vérification en cours...'}
        </button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #FFB6C1, #87CEEB)',
    padding: '20px',
  },
  card: {
    backgroundColor: 'white',
    padding: '40px',
    borderRadius: '24px',
    maxWidth: '500px',
    width: '100%',
    textAlign: 'center',
    position: 'relative',
  },
  backBtn: {
    position: 'absolute',
    top: '15px',
    left: '20px',
    background: 'none',
    border: 'none',
    fontSize: '1.2rem',
    cursor: 'pointer',
    color: '#888',
  },
  title: {
    fontSize: '2rem',
    background: 'linear-gradient(45deg, #FF69B4, #4A90D9)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    marginBottom: '10px',
  },
  subtitle: {
    color: '#888',
    marginBottom: '25px',
  },
  verifyBox: {
    backgroundColor: '#f8f9fa',
    borderRadius: '15px',
    padding: '20px',
    marginBottom: '20px',
    textAlign: 'left',
  },
  info: {
    margin: '10px 0',
    color: '#555',
  },
  sendBtn: {
    width: '100%',
    padding: '10px',
    borderRadius: '10px',
    border: 'none',
    background: '#4A90D9',
    color: 'white',
    fontWeight: 'bold',
    cursor: 'pointer',
    marginTop: '10px',
  },
  codeInput: {
    display: 'flex',
    gap: '10px',
    marginTop: '10px',
  },
  input: {
    flex: 1,
    padding: '10px',
    borderRadius: '10px',
    border: '2px solid #ddd',
    fontSize: '1rem',
    textAlign: 'center',
    letterSpacing: '5px',
  },
  verifyBtn: {
    padding: '10px 20px',
    borderRadius: '10px',
    border: 'none',
    background: '#4CAF50',
    color: 'white',
    fontWeight: 'bold',
    cursor: 'pointer',
  },
  message: {
    color: '#FF1493',
    fontWeight: 'bold',
    margin: '10px 0',
  },
  continueBtn: {
    width: '100%',
    padding: '14px',
    borderRadius: '12px',
    border: 'none',
    background: 'linear-gradient(45deg, #FF6B6B, #FF1493)',
    color: 'white',
    fontSize: '1.2rem',
    fontWeight: 'bold',
    cursor: 'pointer',
    marginTop: '10px',
    opacity: (props) => props.disabled ? 0.5 : 1,
  },
};

export default Verify;
